248→export const uploadJournalContentService = async(
249→    content,
250→    title,
251→    userId,
252→    postType = POST_TYPE_TEXT,
253→    canvasDocInput = null,
254→    remixSourceJournalId = null,
255→    isRemix = false,
256→    promptId = null
257→) =>{
258→    if(!userId){
259→        console.error('userId is undefined');
260→        throw {status: 400, error: 'userId is undefined'};
261→    }
262→
263→    const resolvedPostType = normalizePostType(postType);
264→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
265→
266→    if(!trimmedTitle){
267→        console.error('title is missing!');
268→        throw {status: 400, error: 'title is missing!'};
269→    }
270→
271→    let embeddingBody = '';
272→    const shouldSaveRemixMetadata = Boolean(
273→        remixSourceJournalId
274→        && typeof remixSourceJournalId === 'string'
275→        && remixSourceJournalId.trim()
276→    );
277→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
278→    let payload = {
279→        user_id: userId,
280→        title: trimmedTitle,
281→        post_type: resolvedPostType
282→    };
283→
284→    if(resolvedPostType === POST_TYPE_CANVAS){
285→        let parsedCanvasDoc = null;
286→        try {
287→            parsedCanvasDoc = parseCanvasDocInput(canvasDocInput);
288→        } catch (error) {
289→            console.error('invalid canvas doc on insert:', error?.message || error);
290→            throw {status: 400, error: 'invalid canvas_doc'};
291→        }
292→
293→        if(!parsedCanvasDoc){
294→            console.error('canvas_doc is missing for canvas post');
295→            throw {status: 400, error: 'canvas_doc is missing'};
296→        }
297→
298→        embeddingBody = extractCanvasPlainText(parsedCanvasDoc);
299→        payload = {
300→            ...payload,
301→            content: null,
302→            canvas_doc: parsedCanvasDoc
303→        };
304→    } else {
305→        if(!content){
306→            console.error('content is missing for text post!');
307→            throw {status: 400, error: 'content is missing for text post'};
308→        }
309→
310→        const parseData = parseTextContentSafely(content);
311→        if(!parseData){
312→            console.error('error while parsing text content data');
313→            throw {status: 400, error: 'error while parsing text content data'};
314→        }
315→
316→        embeddingBody = parseData.wholeText || '';
317→        payload = {
318→            ...payload,
319→            content: content,
320→            canvas_doc: null
321→        };
322→    }
323→
324→    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
325→
326→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
327→        console.error('error while generating embeddings on a post!');
328→        throw {status: 400, error: 'error while generating embeddings on a post!'};
329→    }
330→
331→    const insertPayload = {
332→        ...payload,
333→        embeddings: embeddingResult
334→    };
335→
336→    if(normalizedIsRemix){
337→        insertPayload.is_remix = true;
338→    }
339→    if(shouldSaveRemixMetadata){
340→        insertPayload.remix_source_journal_id = remixSourceJournalId.trim();
341→    }
342→    if(promptId){
343→        const parsedPromptId = parseInt(promptId, 10);
344→        if(!isNaN(parsedPromptId)){
345→            insertPayload.prompt_id = parsedPromptId;
346→        }
347→    }
348→
349→    try {
350→        const {count: postCount} = await supabase
351→            .from('journals')
352→            .select('id', {count: 'exact', head: true})
353→            .eq('user_id', userId);
354→        const home = userHomeCoords(userId);
355→        const offset = spiralLayout(postCount || 0);
356→        insertPayload.universe_x = home.x + offset.dx;
357→        insertPayload.universe_y = home.y + offset.dy;
358→    } catch (coordErr) {
359→        console.error('non-fatal: failed to compute universe coords:', coordErr?.message || coordErr);
360→    }
361→
362→    let {error} = await supabase
363→    .from('journals')
364→    .insert(insertPayload);
365→
366→    if(error){
367→        const missingRemixColumns = error?.message?.includes('is_remix') || error?.message?.includes('remix_source_journal_id');
368→        if(missingRemixColumns){
369→            const fallbackPayload = {
370→                ...payload,
371→                embeddings: embeddingResult
372→            };
373→
374→            const retry = await supabase
375→            .from('journals')
376→            .insert(fallbackPayload);
377→            error = retry.error;
378→        }
379→    }
380→
381→    if(error){
382→        console.error('supabase error while uploading content:',error.message);
383→        throw {status: 500, error: 'supabase error while uploading content'};
384→    }
385→
386→    // Non-fatal: incrementally update galaxy positions for this user
387→    try {
388→        incrementalSettleForUser(userId).catch(err =>
389→            console.error('non-fatal: incremental settle failed:', err?.message || err)
390→        );
391→    } catch (settleErr) {
392→        console.error('non-fatal: incremental settle failed:', settleErr?.message || settleErr);
393→    }
394→
395→    // Non-fatal: record publish for writing streak
396→    try {
397→        const { recordPublishForStreak } = await import('./streakService.js');
398→        recordPublishForStreak(userId).catch(err =>
399→            console.error('non-fatal: streak record failed:', err?.message || err)
400→        );
401→    } catch (streakErr) {
402→        console.error('non-fatal: streak record failed:', streakErr?.message || streakErr);
403→    }
404→
405→    return true;
406→}
