408→export const updateJournalService = async(content, title, journalId, userId, postType = null, canvasDocInput = null) => {
409→    if(!journalId){
410→        console.error('journalid is undefined');
411→        throw {status: 400, error: 'journalId is undefined'}
412→    }
413→
414→    if(!userId){
415→        console.error('userId is undefined')
416→        throw({status: 400, error: 'userId is undefined'})
417→    }
418→
419→    const resolvedRequestedPostType = postType ? normalizePostType(postType) : null;
420→
421→    const {data: existingJournal, error: existingJournalError} = await supabase
422→    .from('journals')
423→    .select('id, user_id, content, title, post_type, canvas_doc')
424→    .eq('id', journalId)
425→    .eq('user_id', userId)
426→    .maybeSingle();
427→
428→    if(existingJournalError){
429→        console.error('failed to fetch existing journal for update', existingJournalError.message);
430→        throw {status: 500, error: 'failed to fetch existing journal for update'};
431→    }
432→
433→    if(!existingJournal){
434→        console.error('journal not found for update');
435→        throw {status: 404, error: 'journal not found for update'};
436→    }
437→
438→    const resolvedPostType = resolvedRequestedPostType || normalizePostType(existingJournal.post_type);
439→    const resolvedTitle = typeof title === 'string' && title.trim() ? title.trim() : existingJournal.title;
440→    if(!resolvedTitle){
441→        console.error('title is undefined');
442→        throw {status: 400, error: 'title is undefined'};
443→    }
444→
445→    let resolvedContent = existingJournal.content;
446→    let resolvedCanvasDoc = existingJournal.canvas_doc;
447→    let embeddingBody = '';
448→
449→    if(resolvedPostType === POST_TYPE_CANVAS){
450→        if(canvasDocInput){
451→            try {
452→                resolvedCanvasDoc = parseCanvasDocInput(canvasDocInput);
453→            } catch (error) {
454→                console.error('invalid canvas doc on update:', error?.message || error);
455→                throw {status: 400, error: 'invalid canvas_doc'};
456→            }
457→        }
458→
459→        if(!resolvedCanvasDoc){
460→            console.error('canvas_doc is missing for canvas post update');
461→            throw {status: 400, error: 'canvas_doc is missing for canvas post update'};
462→        }
463→
464→        resolvedContent = null;
465→        embeddingBody = extractCanvasPlainText(resolvedCanvasDoc);
466→    } else {
467→        if(typeof content === 'string' && content.trim()){
468→            resolvedContent = content;
469→        }
470→
471→        if(!resolvedContent){
472→            console.error('text content is missing for text post update');
473→            throw {status: 400, error: 'text content is missing for text post update'};
474→        }
475→
476→        const parseData = parseTextContentSafely(resolvedContent);
477→        if(!parseData){
478→            console.error('failed to parse text content for update');
479→            throw {status: 400, error: 'failed to parse text content for update'};
480→        }
481→
482→        resolvedCanvasDoc = null;
483→        embeddingBody = parseData.wholeText || '';
484→    }
485→
486→    const embeddings = await GenerateEmbeddings(resolvedTitle, embeddingBody);
487→
488→    const embeddingResult = embeddings;
489→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
490→        console.error('failed to generate embeddings')
491→        throw {status: 400, error: 'failed to generate embeddings'};
492→    }
493→
494→    const journalData = {
495→        content: resolvedContent,
496→        title: resolvedTitle,
497→        post_type: resolvedPostType,
498→        canvas_doc: resolvedCanvasDoc,
499→        embeddings: embeddings
500→    }
501→
502→    const {data, error} = await supabase
503→    .from('journals')
504→    .update(journalData)
505→    .eq('id', journalId)
506→    .eq('user_id', userId)
507→
508→    if(error){
509→        console.error('supabase error while uploading content:', error.message);
510→        throw{status: 500, error: 'supabase error while uploading content'};
511→    }
512→
513→    return true;
514→}
