 845→            upstreamContentType: null,
 846→            upstreamBytes: null,
 847→            outputBytes: null,
 848→        },
 849→    };
 850→
 851→    const fallbackWithReason = (reason) => {
 852→        debugPayload.ok = false;
 853→        debugPayload.fallback = true;
 854→        debugPayload.stage = 'fallback';
 855→        debugPayload.reason = reason;
 856→        if (debugMode) {
