 866→            return fallbackWithReason('journal_not_found');
 867→        }
 868→
 869→        const shareMeta = buildShareMetaFromJournal(journal);
 870→        debugPayload.stage = 'candidate_extracted';
 871→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
 872→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
 873→
 874→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
 875→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
 876→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
