501→
502→    const {data: signedUrlData, error: signedUrlError} = await supabase.storage
503→        .from(bucket)
504→        .createSignedUrl(path, 60 * 60);
505→
506→    if(!signedUrlError && signedUrlData?.signedUrl){
507→        return signedUrlData.signedUrl;
508→    }
509→
510→    return null;
511→};
